namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // ── CreateOrder ──────────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 25m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45m, order.Total); // 10*2 + 25*1
        Assert.AreSame(items, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsUniqueId()
    {
        var items = CreateItems(("Widget", 5m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.IsTrue(Guid.TryParse(order.Id, out _), "Id should be a valid GUID.");
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 5m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsDifferentIds()
    {
        var items1 = CreateItems(("A", 1m, 1));
        var items2 = CreateItems(("B", 2m, 1));

        var order1 = _service.CreateOrder("cust-1", items1);
        var order2 = _service.CreateOrder("cust-1", items2);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_WithVariousItems_CalculatesTotalCorrectly(
        string description, decimal price, int quantity, decimal expectedTotal)
    {
        var items = CreateItems(("Product", price, quantity));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total, $"Failed for: {description}");
    }

    public static IEnumerable<(string description, decimal price, int quantity, decimal expectedTotal)> TotalCalculationData =>
    [
        ("single item", 10m, 1, 10m),
        ("multiple quantity", 7.50m, 4, 30m),
        ("zero price", 0m, 5, 0m),
        ("zero quantity", 15m, 0, 0m),
    ];

    // ── CreateOrder – validation ─────────────────────────────────────

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    // ── GetOrder ─────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var found = _service.GetOrder(created.Id);

        Assert.AreSame(created, found);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ── GetOrdersByCustomer ──────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_WithOrders_ReturnsMatchingOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("nonexistent");

        Assert.AreEqual(0, result.Count);
    }
}

